class Solution {
public:
    string frequencySort(string s) {
        unordered_map<char, int> freq;
        for (char c : s) {
            freq[c]++;
        }

        auto cmp = [](const pair<char, int>& a, const pair<char, int>& b) {
            return a.second < b.second;
        };

        priority_queue<pair<char, int>, vector<pair<char, int>>, decltype(cmp)> maxHeap(cmp);
        for (auto& it : freq) {
            maxHeap.push(it);
        }

        string result;
        while (!maxHeap.empty()) {
            auto top = maxHeap.top();
            maxHeap.pop();
            result.append(top.second, top.first);
        }

        return result;
    }
};
efficiency: HIGH
time complexity: O(n log k)
space complexity: O(n)
energy implications: LOW
explanation: Utilizes a max heap to efficiently sort characters by frequency, achieving a good balance between time and space complexity.
